# --- plot helper (hidden) — letters as numbers, before and after XOR ---
# The cipher curve is the student's OWN xor_encrypt output. Falls back to a
# built-in XOR until it works. The plain-letters curve is a fixed comparison.
def __plot(message, key):
    plain = [[i, ord(c)] for i, c in enumerate(message)]
    try:
        nums = xor_encrypt(message, key)   # <- the STUDENT's function
        if isinstance(nums, list) and len(nums) == len(message):
            cipher = [[i, nums[i]] for i in range(len(nums))]
            clabel = "after XOR (your cipher)"
        else:
            raise ValueError()
    except Exception:
        cipher = [[i, ord(c) ^ key] for i, c in enumerate(message)]
        clabel = "after XOR (the cipher)"
    return [
        {"name": clabel, "points": cipher, "highlight": True},
        {"name": "plain letters (as numbers)", "points": plain, "highlight": False},
    ]
